const ctx = items[0].json;
const primaryModel = (ctx.model || 'qwen3.5:27b').toString();
const fallbackModel = (ctx.model_fallback || '').toString().trim();
let activeModel = primaryModel;

function nowIso() {
  return new Date().toISOString();
}

function shortText(value, maxLen = 220) {
  const text = typeof value === 'string' ? value : JSON.stringify(value || '');
  if (text.length <= maxLen) return text;
  return text.slice(0, maxLen - 3) + '...';
}

function clamp01(value, fallback = 0.5) {
  const n = Number(value);
  if (!Number.isFinite(n)) return fallback;
  if (n < 0) return 0;
  if (n > 1) return 1;
  return n;
}

function clamp10(value, fallback = 6) {
  const n = Number(value);
  if (!Number.isFinite(n)) return fallback;
  if (n < 0) return 0;
  if (n > 10) return 10;
  return n;
}

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function requiredKeys(schemaName) {
  const schema = (ctx.schemas || {})[schemaName] || {};
  return Array.isArray(schema.required) ? schema.required : [];
}

function assertRequired(obj, keys, label) {
  for (const key of keys) {
    if (!(key in obj)) {
      throw new Error(label + ' missing required key: ' + key);
    }
  }
}

function extractJsonCandidate(rawText) {
  if (typeof rawText !== 'string') {
    throw new Error('Model output is not a string');
  }

  const fenced = rawText.match(new RegExp('\\x60\\x60\\x60(?:json)?\\s*([\\s\\S]*?)\\x60\\x60\\x60', 'i'));
  const text = (fenced ? fenced[1] : rawText).trim();

  try {
    return JSON.parse(text);
  } catch (error) {
    // continue
  }

  const startCandidates = [];
  const objStart = text.indexOf('{');
  const arrStart = text.indexOf('[');
  if (objStart >= 0) startCandidates.push(objStart);
  if (arrStart >= 0) startCandidates.push(arrStart);
  if (!startCandidates.length) {
    throw new Error('No JSON object or array start found in model output');
  }

  const start = Math.min(...startCandidates);
  const firstChar = text[start];
  const openChar = firstChar;
  const closeChar = firstChar === '{' ? '}' : ']';

  let depth = 0;
  let inString = false;
  let escaped = false;
  for (let i = start; i < text.length; i++) {
    const ch = text[i];
    if (inString) {
      if (escaped) {
        escaped = false;
      } else if (ch === '\\\\') {
        escaped = true;
      } else if (ch === '"') {
        inString = false;
      }
      continue;
    }

    if (ch === '"') {
      inString = true;
      continue;
    }
    if (ch === openChar) depth += 1;
    if (ch === closeChar) {
      depth -= 1;
      if (depth === 0) {
        const candidate = text.slice(start, i + 1);
        return JSON.parse(candidate);
      }
    }
  }

  throw new Error('Could not extract valid JSON payload from model output');
}

async function callOllama(systemPrompt, userPrompt, temperature = 0.3) {
  const candidates = [];
  if (activeModel) candidates.push(activeModel);
  if (fallbackModel && !candidates.includes(fallbackModel)) {
    candidates.push(fallbackModel);
  }

  let lastError;

  for (let i = 0; i < candidates.length; i++) {
    const modelName = candidates[i];
    try {
      const data = await this.helpers.httpRequest({
        method: 'POST',
        url: 'http://ollama:11434/api/chat',
        body: {
          model: modelName,
          stream: false,
          messages: [
            { role: 'system', content: systemPrompt },
            { role: 'user', content: userPrompt }
          ],
          options: {
            temperature,
            num_predict: 700
          }
        },
        json: true
      });

      const text = data && data.message ? data.message.content : data.response;
      if (!text) {
        throw new Error('Ollama response has no message content');
      }

      activeModel = modelName;
      ctx.active_model = activeModel;

      return {
        raw: text,
        parsed: extractJsonCandidate(text)
      };
    } catch (error) {
      const status = error && error.response && error.response.status
        ? error.response.status
        : (error && error.httpCode ? error.httpCode : 0);

      const apiError = error && error.response && error.response.data && error.response.data.error
        ? error.response.data.error
        : '';
      const details = [error && error.message ? error.message : '', apiError].filter(Boolean).join(' | ');

      const isMemoryError = status === 500
        && /model requires more system memory|model request too large for system/i.test(details);

      if (isMemoryError && modelName === primaryModel && fallbackModel && fallbackModel !== primaryModel) {
        ctx.model_switch_log = Array.isArray(ctx.model_switch_log) ? ctx.model_switch_log : [];
        ctx.model_switch_log.push({
          at: nowIso(),
          from: primaryModel,
          to: fallbackModel,
          reason: details || 'primary model exceeds available memory'
        });
        continue;
      }

      lastError = new Error('Ollama call failed for model "' + modelName + '": ' + (details || 'unknown error'));

      if (i < candidates.length - 1) {
        continue;
      }

      throw lastError;
    }
  }

  throw lastError || new Error('Ollama call failed');
}

async function callSearx(query) {
  const maxAttempts = 4;
  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
    try {
      return await this.helpers.httpRequest({
        method: 'GET',
        url: 'http://searxng:8080/search',
        qs: {
          format: 'json',
          language: 'de-DE',
          q: query
        },
        headers: {
          'User-Agent': 'Mozilla/5.0 (sandbank-n8n-research)'
        },
        json: true
      });
    } catch (error) {
      const status = error && error.response && error.response.status
        ? error.response.status
        : (error && error.httpCode ? error.httpCode : 0);
      if (status === 429 && attempt < maxAttempts) {
        await sleep(500 * attempt);
        continue;
      }
      throw new Error('SearXNG call failed for query \"' + query + '\": ' + (status || 'unknown') + ' - ' + (error.message || 'request error'));
    }
  }

  throw new Error('SearXNG call failed after retries for query \"' + query + '\"');
}

function addStageLog(step, agent, status, inputRef, outputRef, qualityScore, notes) {
  ctx.stage_logs.push({
    step,
    agent,
    status,
    input_ref: inputRef,
    output_ref: outputRef,
    quality_score: Number.isFinite(Number(qualityScore)) ? Number(qualityScore) : 0,
    notes,
    ts: nowIso()
  });
}

function normalizeDraftPackage(candidate, previousDraftPackage) {
  if (candidate && Array.isArray(candidate.drafts) && candidate.drafts.length > 0) {
    const normalizedDrafts = candidate.drafts.map((draft, idx) => ({
      platform: (draft.platform || 'linkedin').toString().toLowerCase(),
      title: (draft.title || ('Draft ' + (idx + 1))).toString(),
      body: (draft.body || '').toString(),
      cta: (draft.cta || '').toString(),
      hashtags: Array.isArray(draft.hashtags) ? draft.hashtags : [],
      notes: Array.isArray(draft.notes) ? draft.notes : []
    }));

    return {
      topic: (candidate.topic || (previousDraftPackage && previousDraftPackage.topic) || 'Untitled topic').toString(),
      drafts: normalizedDrafts
    };
  }

  if (candidate && candidate.platform && candidate.title && candidate.body && candidate.cta) {
    return {
      topic: (candidate.topic || (previousDraftPackage && previousDraftPackage.topic) || 'Untitled topic').toString(),
      drafts: [
        {
          platform: candidate.platform.toString().toLowerCase(),
          title: candidate.title.toString(),
          body: candidate.body.toString(),
          cta: candidate.cta.toString(),
          hashtags: Array.isArray(candidate.hashtags) ? candidate.hashtags : [],
          notes: Array.isArray(candidate.notes) ? candidate.notes : []
        }
      ]
    };
  }

  if (previousDraftPackage) return previousDraftPackage;
  throw new Error('Could not normalize draft package');
}

function normalizeCritique(critique, stageName) {
  const normalized = (critique && critique.critique_report) ? critique.critique_report : critique;
  assertRequired(normalized, requiredKeys('critique_report'), stageName);
  return {
    stage: (normalized.stage || stageName).toString(),
    score: clamp10(normalized.score, 6),
    issues: Array.isArray(normalized.issues)
      ? normalized.issues.map((issue) => ({
          severity: ['low', 'medium', 'high'].includes(issue && issue.severity) ? issue.severity : 'medium',
          message: (issue && issue.message ? issue.message : 'Unspecified issue').toString()
        }))
      : [],
    improved_draft: normalized.improved_draft || {}
  };
}

function computeAverage(values) {
  if (!values.length) return 0;
  return values.reduce((sum, value) => sum + value, 0) / values.length;
}

function sanitizeSlug(value) {
  return (value || 'post')
    .toString()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 80);
}

// Stage 1: Research Intake
const priorityRank = { high: 3, medium: 2, low: 1 };
const topQueries = (ctx.research_queries || [])
  .slice()
  .sort((a, b) => (priorityRank[b.priority] || 0) - (priorityRank[a.priority] || 0))
  .slice(0, 3);

const rawSignals = [];
const skippedQueries = [];
for (const query of topQueries) {
  try {
    const response = await callSearx(query.query);
    const results = Array.isArray(response.results) ? response.results.slice(0, 4) : [];
    for (const result of results) {
      rawSignals.push({
        query: query.query,
        source_type: query.source_type || 'web',
        title: result.title || '',
        url: result.url || '',
        summary: result.content || result.snippet || '',
        published_at: result.publishedDate || ''
      });
    }
  } catch (error) {
    skippedQueries.push({
      query: query.query,
      reason: error.message || 'unknown'
    });
  }
  await sleep(250);
}

if (!rawSignals.length) {
  throw new Error('Stage 1 did not collect any research signals. Skipped queries: ' + JSON.stringify(skippedQueries));
}

const stage1Prompt = [
  ctx.prompts.agent1_research,
  'Return JSON only.',
  'Required keys: ' + requiredKeys('evidence_packet').join(', '),
  'Brand brief (short): ' + JSON.stringify({
    values: ctx.brand_brief.values,
    tone: ctx.brand_brief.tone,
    positioning: ctx.brand_brief.positioning
  }),
  'Search signals: ' + JSON.stringify(rawSignals)
].join('\n\n');

const stage1Result = await callOllama(
  'You are an evidence-focused analyst. Return valid JSON only, no markdown.',
  stage1Prompt,
  0.2
);

let evidencePackets = [];
if (Array.isArray(stage1Result.parsed)) {
  evidencePackets = stage1Result.parsed;
} else if (stage1Result.parsed && Array.isArray(stage1Result.parsed.packets)) {
  evidencePackets = stage1Result.parsed.packets;
}

if (!evidencePackets.length) {
  throw new Error('Stage 1 returned no evidence packets');
}

const evidenceReq = requiredKeys('evidence_packet');
evidencePackets = evidencePackets.map((packet, idx) => {
  assertRequired(packet, evidenceReq, 'agent1_evidence[' + idx + ']');
  return {
    query: packet.query.toString(),
    source_type: packet.source_type.toString(),
    title: packet.title.toString(),
    url: packet.url.toString(),
    published_at: (packet.published_at || '').toString(),
    summary: packet.summary.toString(),
    key_points: Array.isArray(packet.key_points) ? packet.key_points.map((v) => v.toString()) : [],
    icp_fit_score: clamp01(packet.icp_fit_score, 0.5),
    product_relevance_score: clamp01(packet.product_relevance_score, 0.5),
    evidence_strength: clamp01(packet.evidence_strength, 0.5),
    risk_notes: Array.isArray(packet.risk_notes) ? packet.risk_notes.map((v) => v.toString()) : []
  };
});

ctx.artifacts.agent1_evidence_packets = evidencePackets;
addStageLog(
  1,
  'research_intake',
  'ok',
  'run/' + ctx.run_id + '/agent1/input',
  'run/' + ctx.run_id + '/agent1/evidence_packets',
  computeAverage(evidencePackets.map((p) => p.evidence_strength)),
  'Packets: ' + evidencePackets.length + (skippedQueries.length ? '; skipped_queries=' + skippedQueries.length : '')
);

// Stage 2: Topic Fit
const compactEvidence = evidencePackets.slice(0, 12).map((p) => ({
  title: p.title,
  summary: p.summary,
  icp_fit_score: p.icp_fit_score,
  product_relevance_score: p.product_relevance_score,
  evidence_strength: p.evidence_strength,
  url: p.url
}));

const stage2Prompt = [
  ctx.prompts.agent2_topic_fit,
  'Return JSON only.',
  'Required keys: ' + requiredKeys('topic_brief').join(', '),
  'Evidence packets: ' + JSON.stringify(compactEvidence),
  'Brand brief tone: ' + JSON.stringify(ctx.brand_brief.tone),
  'Platform profiles: ' + JSON.stringify(ctx.platform_profiles)
].join('\n\n');

const stage2Result = await callOllama(
  'You are a product marketing strategist. Return valid JSON only, no markdown.',
  stage2Prompt,
  0.3
);

const topicBrief = stage2Result.parsed;
assertRequired(topicBrief, requiredKeys('topic_brief'), 'agent2_topic_brief');
topicBrief.confidence = clamp01(topicBrief.confidence, 0.5);
if (!Array.isArray(topicBrief.platform_recommendation) || !topicBrief.platform_recommendation.length) {
  topicBrief.platform_recommendation = ['linkedin'];
}

ctx.artifacts.agent2_topic_brief = topicBrief;
addStageLog(
  2,
  'topic_fit',
  'ok',
  'run/' + ctx.run_id + '/agent2/input',
  'run/' + ctx.run_id + '/agent2/topic_brief',
  topicBrief.confidence,
  shortText(topicBrief.angle, 140)
);

// Stage 3: Draft Factory
const stage3Prompt = [
  ctx.prompts.agent3_draft,
  'Return JSON only.',
  'Required keys: ' + requiredKeys('draft_package').join(', '),
  'Topic brief: ' + JSON.stringify(topicBrief),
  'Brand brief: ' + JSON.stringify(ctx.brand_brief),
  'Platform profiles: ' + JSON.stringify(ctx.platform_profiles)
].join('\n\n');

const stage3Result = await callOllama(
  'You are a senior B2B social copywriter. Return valid JSON only, no markdown.',
  stage3Prompt,
  0.4
);

let currentDraftPackage = normalizeDraftPackage(stage3Result.parsed, null);
assertRequired(currentDraftPackage, requiredKeys('draft_package'), 'agent3_draft_package');
if (!Array.isArray(currentDraftPackage.drafts) || !currentDraftPackage.drafts.length) {
  throw new Error('Stage 3 produced no drafts');
}

ctx.artifacts.agent3_draft_package = currentDraftPackage;
addStageLog(
  3,
  'draft_factory',
  'ok',
  'run/' + ctx.run_id + '/agent3/input',
  'run/' + ctx.run_id + '/agent3/draft_package',
  Math.min(10, currentDraftPackage.drafts.length * 3),
  'Drafts: ' + currentDraftPackage.drafts.length
);

// Stage 4: AI-Sounding Critic
const stage4Prompt = [
  ctx.prompts.agent4_ai_sounding_critic,
  'Return JSON only.',
  'Required keys: ' + requiredKeys('critique_report').join(', '),
  'Draft package: ' + JSON.stringify(currentDraftPackage)
].join('\n\n');

const stage4Result = await callOllama(
  'You are an editorial reviewer focused on human sounding writing. Return valid JSON only.',
  stage4Prompt,
  0.2
);

const critique4 = normalizeCritique(stage4Result.parsed, 'agent4_ai_sounding_critic');
currentDraftPackage = normalizeDraftPackage(critique4.improved_draft, currentDraftPackage);
ctx.artifacts.agent4_critique_report = critique4;
ctx.artifacts.draft_after_agent4 = currentDraftPackage;
addStageLog(
  4,
  'ai_sounding_critic',
  'ok',
  'run/' + ctx.run_id + '/agent4/input',
  'run/' + ctx.run_id + '/agent4/critique_report',
  critique4.score,
  critique4.issues.length + ' issues'
);

// Stage 5: Visual Brief
const stage5Prompt = [
  ctx.prompts.agent5_visual,
  'Return JSON only.',
  'Each array item required keys: ' + requiredKeys('visual_brief').join(', '),
  'Draft package: ' + JSON.stringify(currentDraftPackage),
  'Brand visual rules: ' + JSON.stringify(ctx.brand_brief.visual)
].join('\n\n');

const stage5Result = await callOllama(
  'You are a visual concept specialist for B2B social content. Return valid JSON only.',
  stage5Prompt,
  0.3
);

let visualBriefs = [];
if (Array.isArray(stage5Result.parsed)) {
  visualBriefs = stage5Result.parsed;
} else if (stage5Result.parsed && Array.isArray(stage5Result.parsed.visual_briefs)) {
  visualBriefs = stage5Result.parsed.visual_briefs;
}

if (!visualBriefs.length) {
  throw new Error('Stage 5 produced no visual briefs');
}

const visualReq = requiredKeys('visual_brief');
visualBriefs = visualBriefs.map((brief, idx) => {
  assertRequired(brief, visualReq, 'agent5_visual[' + idx + ']');
  return {
    platform: brief.platform.toString().toLowerCase(),
    visual_prompt: brief.visual_prompt.toString(),
    color_palette: Array.isArray(brief.color_palette) ? brief.color_palette.map((v) => v.toString()) : [],
    composition_constraints: Array.isArray(brief.composition_constraints)
      ? brief.composition_constraints.map((v) => v.toString())
      : []
  };
});

ctx.artifacts.agent5_visual_briefs = visualBriefs;
addStageLog(
  5,
  'visual_brief',
  'ok',
  'run/' + ctx.run_id + '/agent5/input',
  'run/' + ctx.run_id + '/agent5/visual_briefs',
  8,
  'Briefs: ' + visualBriefs.length
);

// Stage 6: Strategy Critic 1
const stage6Prompt = [
  ctx.prompts.agent6_strategy_critic,
  'Return JSON only.',
  'Required keys: ' + requiredKeys('critique_report').join(', '),
  'Draft package: ' + JSON.stringify(currentDraftPackage),
  'Topic brief: ' + JSON.stringify(topicBrief)
].join('\n\n');

const stage6Result = await callOllama(
  'You are a growth-focused social strategy reviewer. Return valid JSON only.',
  stage6Prompt,
  0.2
);

const critique6 = normalizeCritique(stage6Result.parsed, 'agent6_strategy_critic_1');
currentDraftPackage = normalizeDraftPackage(critique6.improved_draft, currentDraftPackage);
ctx.artifacts.agent6_critique_report = critique6;
ctx.artifacts.draft_after_agent6 = currentDraftPackage;
addStageLog(
  6,
  'strategy_critic_1',
  'ok',
  'run/' + ctx.run_id + '/agent6/input',
  'run/' + ctx.run_id + '/agent6/critique_report',
  critique6.score,
  critique6.issues.length + ' issues'
);

// Stage 7: Strategy Critic 2
const stage7Prompt = [
  ctx.prompts.agent7_strategy_critic,
  'Return JSON only.',
  'Required keys: ' + requiredKeys('critique_report').join(', '),
  'Draft package: ' + JSON.stringify(currentDraftPackage),
  'Topic brief: ' + JSON.stringify(topicBrief)
].join('\n\n');

const stage7Result = await callOllama(
  'You are a strict final quality reviewer for brand-safe social writing. Return valid JSON only.',
  stage7Prompt,
  0.2
);

const critique7 = normalizeCritique(stage7Result.parsed, 'agent7_strategy_critic_2');
currentDraftPackage = normalizeDraftPackage(critique7.improved_draft, currentDraftPackage);
ctx.artifacts.agent7_critique_report = critique7;
ctx.artifacts.final_draft_package = currentDraftPackage;
addStageLog(
  7,
  'strategy_critic_2',
  'ok',
  'run/' + ctx.run_id + '/agent7/input',
  'run/' + ctx.run_id + '/agent7/critique_report',
  critique7.score,
  critique7.issues.length + ' issues'
);

// Deterministic final Obsidian payload (factory output)
const primaryDraft = currentDraftPackage.drafts[0];
const datePrefix = new Date().toISOString().slice(0, 10);
const topicSlug = sanitizeSlug(currentDraftPackage.topic || topicBrief.topic || 'social-post');
const fileName = datePrefix + ' - ' + primaryDraft.platform + ' - ' + topicSlug + '.md';

const finalDescription = shortText(primaryDraft.body.replace(/\s+/g, ' ').trim(), 160);
const hashtags = Array.isArray(primaryDraft.hashtags) ? primaryDraft.hashtags : [];

const markdownParts = [];
markdownParts.push('# ' + (primaryDraft.title || 'Social post draft'));
markdownParts.push('');
markdownParts.push('## Hook');
markdownParts.push((primaryDraft.title || '').toString());
markdownParts.push('');
markdownParts.push('## Body');
markdownParts.push((primaryDraft.body || '').toString());
markdownParts.push('');
markdownParts.push('## CTA');
markdownParts.push((primaryDraft.cta || '').toString());
if (hashtags.length) {
  markdownParts.push('');
  markdownParts.push('## Hashtags');
  markdownParts.push(hashtags.join(' '));
}

ctx.final_note = {
  file_name: fileName,
  description: finalDescription,
  channel: primaryDraft.platform || 'linkedin',
  format: 'text-post',
  status: 'draft',
  link: '',
  markdown_body: markdownParts.join('\n')
};

ctx.topic = currentDraftPackage.topic || topicBrief.topic || '';
ctx.visual_briefs = visualBriefs;
ctx.stage_count = ctx.stage_logs.length;
ctx.model_used = activeModel;
ctx.completed_at = nowIso();

return [{ json: ctx }];

const ctx = items[0].json;

function safeYaml(value) {
  return (value || '').toString().replace(/\n/g, ' ').replace(/"/g, '\\"');
}

function markdownTable(stageLogs) {
  const header = [
    '| step | agent | status | input_ref | output_ref | quality_score | notes | ts |',
    '|---|---|---|---|---|---:|---|---|'
  ];

  const rows = stageLogs.map((entry) => {
    return [
      '| ' + entry.step,
      entry.agent,
      entry.status,
      entry.input_ref,
      entry.output_ref,
      Number(entry.quality_score || 0).toFixed(2),
      (entry.notes || '').toString().replace(/\|/g, '/'),
      entry.ts + ' |'
    ].join(' | ');
  });

  return header.concat(rows).join('\n');
}

const finalNote = ctx.final_note;
if (!finalNote) {
  throw new Error('No final note payload present');
}

const postFrontmatter = [
  '---',
  'description: "' + safeYaml(finalNote.description) + '"',
  'channel: ' + safeYaml(finalNote.channel),
  'format: ' + safeYaml(finalNote.format),
  'status: ' + safeYaml(finalNote.status),
  'link: "' + safeYaml(finalNote.link) + '"',
  'run_id: ' + safeYaml(ctx.run_id),
  '---',
  ''
].join('\n');

const postMarkdown = postFrontmatter + finalNote.markdown_body;
const postPath = ctx.obsidian_notes_dir + '/' + finalNote.file_name;

const stepsFrontmatter = [
  '---',
  'type: social-pipeline-run',
  'run_id: ' + safeYaml(ctx.run_id),
  'created_at: ' + safeYaml(ctx.created_at),
  'completed_at: ' + safeYaml(ctx.completed_at),
  'status: completed',
  'topic: "' + safeYaml(ctx.topic) + '"',
  'model_requested: ' + safeYaml(ctx.model),
  'model_used: ' + safeYaml(ctx.model_used || ctx.active_model || ctx.model),
  '---',
  ''
].join('\n');

const stepsBody = [
  '# Run ' + ctx.run_id,
  '',
  markdownTable(ctx.stage_logs || []),
  '',
  '## Final Output',
  '- post_note_path: ' + postPath,
  '- final_status: draft_ready',
  '- publish_decision: pending_review',
  '',
  '## Stage Artifacts (summary)',
  '- evidence_packets: ' + ((ctx.artifacts.agent1_evidence_packets || []).length || 0),
  '- selected_topic: ' + safeYaml(ctx.topic),
  '- visual_briefs: ' + ((ctx.artifacts.agent5_visual_briefs || []).length || 0),
  '',
  '## Model Selection',
  '- requested: ' + safeYaml(ctx.model),
  '- used: ' + safeYaml(ctx.model_used || ctx.active_model || ctx.model),
  '- switches: ' + JSON.stringify(ctx.model_switch_log || [])
].join('\n');

const stepsMarkdown = stepsFrontmatter + stepsBody;
const stepsPath = ctx.obsidian_steps_dir + '/' + ctx.run_id + '.md';

